# Добавляем __str__ — для print() и str()
class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __str__(self):
        return f'Point({self.x}, {self.y})'

    def __repr__(self):
        return f'Point(x={self.x}, y={self.y})'

p = Point(3, 4)
print(p)        # Point(3, 4) — использует __str__
print(str(p))   # Point(3, 4)
print(repr(p))  # Point(x=3, y=4) — используется в отладке

class Playlist:
    def __init__(self, name):
        self.name = name
        self.songs = []

    def add(self, song):
        self.songs.append(song)

    def __len__(self):
        return len(self.songs)

    def __bool__(self):
        return len(self.songs) > 0

    def __str__(self):
        return f'Плейлист "{self.name}" ({len(self)} треков)'

pl = Playlist('Любимые')
print(len(pl))    # 0
print(bool(pl))   # False — плейлист пустой

pl.add('Song 1')
pl.add('Song 2')
pl.add('Song 3')

print(len(pl))    # 3
print(bool(pl))   # True
print(pl)         # Плейлист "Любимые" (3 треков)

if pl:
    print('Плейлист не пустой')  # выведется это

class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __str__(self):
        return f'Vector({self.x}, {self.y})'

    def __add__(self, other):   # v1 + v2
        return Vector(self.x + other.x, self.y + other.y)

    def __mul__(self, n):       # v * число
        return Vector(self.x * n, self.y * n)

    def __len__(self):
        # длина вектора (целая часть)
        return int((self.x ** 2 + self.y ** 2) ** 0.5)

v1 = Vector(1, 2)
v2 = Vector(3, 4)

print(v1 + v2)   # Vector(4, 6)
print(v1 * 3)    # Vector(3, 6)
print(len(v2))   # 5  (3-4-5 прямоугольный треугольник)

class Money:
    def __init__(self, amount, currency='RUB'):
        self.amount = amount
        self.currency = currency

    def __str__(self):
        return f'{self.amount:.2f} {self.currency}'

    def __repr__(self):
        return f'Money({self.amount}, "{self.currency}")'

    def __add__(self, other):
        if self.currency != other.currency:
            raise ValueError('Нельзя складывать разные валюты')
        return Money(self.amount + other.amount, self.currency)

    def __eq__(self, other):
        return self.amount == other.amount and self.currency == other.currency

    def __lt__(self, other):
        return self.amount < other.amount

price = Money(100)
tax = Money(18)
total = price + tax

print(price)         # 100.00 RUB
print(total)         # 118.00 RUB
print(price < total) # True
print(repr(price))   # Money(100, "RUB")

